/*
 * sqrt() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly sqrt  (test_sqrt_opt.elf)
 *   2. Linked with toolchain's default sqrt       (test_sqrt_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static void emit(double x)
{
    double r = sqrt(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zeros */
    emit(0.0);
    emit(-0.0);

    /* NaN */
    emit_u(0x7ff8000000000000ULL); /* qNaN */
    emit_u(0x7ff0000000000001ULL); /* sNaN */
    emit_u(0xfff8000000000000ULL); /* -NaN */

    /* Infinity */
    emit_u(0x7ff0000000000000ULL); /* +Inf */
    emit_u(0xfff0000000000000ULL); /* -Inf */
}

/* 2. Tiny values: sqrt(x) ~ sqrt(x) */
static void test_tiny(void)
{
    emit_u(0x0000000000000001ULL); /* min denorm */
    emit_u(0x8000000000000001ULL);
    emit_u(0x0008000000000000ULL); /* mid denorm */
    emit_u(0x8008000000000000ULL);
    emit_u(0x000fffffffffffffULL); /* max denorm */
    emit_u(0x800fffffffffffffULL);
    emit(DBL_MIN);
    emit(-DBL_MIN);
    emit(1.0e-150);
    emit(-1.0e-150);
    emit(1.0e-50);
    emit(-1.0e-50);
}

/* 3. Known mathematical values (Pythagorean triples) */
static void test_known(void)
{
    /* Perfect squares and Pythagorean relations */
    emit(1.0);   /* sqrt(1) = 1 */
    emit(4.0);   /* sqrt(4) = 2 */
    emit(9.0);   /* sqrt(9) = 3 */
    emit(16.0);  /* sqrt(16) = 4 */
    emit(25.0);  /* sqrt(25) = 5 */
    emit(100.0); /* sqrt(100) = 10 */

    /* Pythagorean triples: 3-4-5 */
    emit(9.0);   /* 3^2 */
    emit(16.0);  /* 4^2 */
    emit(25.0);  /* 5^2 (sqrt(9+16)) */

    /* Pythagorean triples: 5-12-13 */
    emit(25.0);  /* 5^2 */
    emit(144.0); /* 12^2 */
    emit(169.0); /* 13^2 (sqrt(25+144)) */

    /* Irrational values */
    emit(2.0);   /* sqrt(2) */
    emit(3.0);   /* sqrt(3) */
    emit(0.5);   /* sqrt(0.5) */
}

/* 4. Large arguments */
static void test_large(void)
{
    double vals[] = {
        1.0e10, 1.0e20, 1.0e100, 1.0e200, 1.0e300,
        -1.0e10, -1.0e20, -1.0e100,
        1000.0, 10000.0, 100000.0,
        -1000.0, -10000.0,
        DBL_MAX, -DBL_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 5. Domain boundaries */
static void test_boundary(void)
{
    double step = 0.01;
    /* Values near 0 */
    for (double x = 0.0; x <= 1.0; x += step)
        emit(x);

    /* Values near perfect squares */
    double bases[] = { 1.0, 10.0, 100.0, 1000.0 };
    int nbases = sizeof(bases) / sizeof(bases[0]);
    for (int i = 0; i < nbases; i++) {
        double base_sq = bases[i] * bases[i];
        emit(base_sq - 0.001);
        emit(base_sq);
        emit(base_sq + 0.001);
    }
}

/* 6. Worst-case rounding */
static void test_hard(void)
{
    double cases[] = {
        u2d(0x3ff0000000000000ULL), /* 1.0 */
        u2d(0x4000000000000000ULL), /* 2.0 */
        u2d(0x4008000000000000ULL), /* 3.0 */
        u2d(0x4010000000000000ULL), /* 4.0 */
        2.0, 3.0, 5.0, 10.0,
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++) {
        emit(cases[i]);
        emit(-cases[i]);
    }
}

/* 7. Sweep [0, 100] in 200 steps */
static void test_sweep(void)
{
    double hi = 100.0;
    int nsteps = 200;
    double step = hi / (double)nsteps;

    /* [0, 100] */
    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);

    /* Negative values (domain error) */
    for (int i = 1; i <= 20; i++)
        emit(-((double)i * step));
}

/* 8. Sample [0, 10] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    uint64_t end = 0x4024000000000000ULL; /* 10.0 */
    for (uint64_t b = 0; b <= end; b += 4194304)
        emit_u(b);
}

/* ------------------------------------------------------------------ */

int main(void)
{
    test_special();
    test_tiny();
    test_known();
    test_large();
    test_boundary();
    test_hard();
    test_sweep();
    test_exhaustive_small();
    return 0;
}

/*
 * pow() test harness — prints (input_hex, output_hex, exp_hex) triplets.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly pow  (test_pow_opt.elf)
 *   2. Linked with toolchain's default pow       (test_pow_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static void emit(double x, double y)
{
    double r = pow(x, y);
    printf("%016llx %016llx %016llx\n",
           (unsigned long long)d2u(x),
           (unsigned long long)d2u(y),
           (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits_x, uint64_t bits_y)
{
    emit(u2d(bits_x), u2d(bits_y));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Base = 0 */
    emit(0.0, 0.5);
    emit(-0.0, 0.5);
    emit(0.0, 2.0);

    /* Base = 1 (identity) */
    emit(1.0, 0.0);
    emit(1.0, 2.0);
    emit(1.0, -2.0);
    emit(1.0, 100.0);

    /* Exponent = 0 (result always 1) */
    emit(2.0, 0.0);
    emit(10.0, 0.0);
    emit(-5.0, 0.0);

    /* NaN and Inf cases */
    emit_u(0x7ff8000000000000ULL, 0x3ff0000000000000ULL); /* qNaN base */
    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL); /* qNaN exp */
    emit_u(0x7ff0000000000000ULL, 0x3ff0000000000000ULL); /* +Inf base */
    emit_u(0xfff0000000000000ULL, 0x3ff0000000000000ULL); /* -Inf base */
}

/* 2. Tiny values */
static void test_tiny(void)
{
    /* Small bases with small exponents */
    emit_u(0x0000000000000001ULL, 0x3ff0000000000000ULL); /* min denorm, exp=1 */
    emit(1.0e-150, 2.0);
    emit(1.0e-150, 0.5);
    emit(1.0e-50, 10.0);
    emit(DBL_MIN, 2.0);
    emit(DBL_MIN, 0.5);

    /* Tiny exponents */
    emit(2.0, 1.0e-100);
    emit(10.0, 1.0e-150);
}

/* 3. Known mathematical values (Pythagorean relations) */
static void test_known(void)
{
    /* Base and exponent pairs: (3,2)=9, (4,2)=16, (5,2)=25 (3-4-5 triple squared) */
    emit(3.0, 2.0);   /* 9 */
    emit(4.0, 2.0);   /* 16 */
    emit(5.0, 2.0);   /* 25 (sqrt(9+16)) */

    /* Base and exponent pairs: (5,2)=25, (12,2)=144, (13,2)=169 (5-12-13 triple squared) */
    emit(5.0, 2.0);   /* 25 */
    emit(12.0, 2.0);  /* 144 */
    emit(13.0, 2.0);  /* 169 */

    /* Powers of 2 */
    emit(2.0, 1.0);
    emit(2.0, 2.0);
    emit(2.0, 3.0);
    emit(2.0, 4.0);
    emit(2.0, 8.0);
    emit(2.0, 10.0);
    emit(2.0, -1.0);
    emit(2.0, -2.0);

    /* Powers of 10 */
    emit(10.0, 1.0);
    emit(10.0, 2.0);
    emit(10.0, 3.0);
    emit(10.0, -1.0);
    emit(10.0, -2.0);

    /* Fractional exponents */
    emit(4.0, 0.5);    /* sqrt(4) = 2 */
    emit(8.0, 0.333333);  /* cbrt(8) ~ 2 */
    emit(16.0, 0.25);  /* 16^(1/4) = 2 */
}

/* 4. Large arguments */
static void test_large(void)
{
    double base_vals[] = {
        1.0e10, 1.0e100, DBL_MAX,
        2.0, 10.0, 100.0,
        -2.0, -10.0,
    };
    double exp_vals[] = {
        2.0, 0.5, 100.0, -1.0, -2.0, 1000.0
    };

    int nbases = sizeof(base_vals) / sizeof(base_vals[0]);
    for (int i = 0; i < nbases; i++) {
        emit(base_vals[i], 2.0);
        emit(base_vals[i], 0.5);
        emit(base_vals[i], -1.0);
    }
}

/* 5. Exponent magnitude sensitivity */
static void test_exponent_range(void)
{
    /* Base 2 with various exponents */
    double exps[] = { -100.0, -10.0, -1.0, -0.5, 0.0, 0.5, 1.0, 10.0, 100.0 };
    int nexps = sizeof(exps) / sizeof(exps[0]);

    for (int i = 0; i < nexps; i++) {
        emit(2.0, exps[i]);
        emit(0.5, exps[i]);
        emit(10.0, exps[i]);
    }
}

/* 6. Worst-case rounding */
static void test_hard(void)
{
    double cases[][2] = {
        { 2.0, 2.0 },
        { 2.0, 3.0 },
        { 3.0, 2.0 },
        { 3.0, 3.0 },
        { 1.5, 4.0 },
        { 1.5, -4.0 },
        { u2d(0x3ff0000000000000ULL), u2d(0x4000000000000000ULL) }, /* 1.0, 2.0 */
        { u2d(0x4000000000000000ULL), u2d(0x4000000000000000ULL) }, /* 2.0, 2.0 */
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++) {
        emit(cases[i][0], cases[i][1]);
        emit(-cases[i][0], cases[i][1]);
    }
}

/* 7. Sweep base [0.5, 10] and exponent [0, 5] */
static void test_sweep(void)
{
    int nbase = 50;
    int nexp = 50;

    for (int i = 0; i <= nbase; i++) {
        double base = 0.5 + (10.0 - 0.5) * (double)i / (double)nbase;
        for (int j = 0; j <= nexp; j++) {
            double exp = (double)j * 5.0 / (double)nexp;
            emit(base, exp);
        }
    }
}

/* 8. Sample critical range with ULP granularity */
static void test_exhaustive_small(void)
{
    /* Base in [1.0, 2.0], exponent in [0, 1] */
    uint64_t base_start = 0x3ff0000000000000ULL; /* 1.0 */
    uint64_t base_end = 0x4000000000000000ULL;   /* 2.0 */
    uint64_t exp_start = 0x0000000000000000ULL;  /* 0.0 */
    uint64_t exp_end = 0x3ff0000000000000ULL;    /* 1.0 */

    for (uint64_t b = base_start; b <= base_end; b += 17179869)
        for (uint64_t e = exp_start; e <= exp_end; e += 17179869)
            emit_u(b, e);
}

/* ------------------------------------------------------------------ */

int main(void)
{
    test_special();
    test_tiny();
    test_known();
    test_large();
    test_exponent_range();
    test_hard();
    test_sweep();
    test_exhaustive_small();
    return 0;
}

