/*
 * pow() test harness — prints (x_hex, y_hex, output_hex) triples.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static void emit(double x, double y)
{
    double r = pow(x, y);
    printf("%016llx %016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(y), (unsigned long long)d2u(r));
}

static void emit_u(uint64_t x_bits, uint64_t y_bits)
{
    emit(u2d(x_bits), u2d(y_bits));
}

/* Test special values */
static void test_special(void)
{
    emit(0.0, 1.0);
    emit(-0.0, 1.0);
    emit(1.0, 0.0);
    emit(1.0, -0.0);
    emit(1.0, INFINITY);
    emit(1.0, -INFINITY);
    emit_u(0x7ff8000000000000ULL, 0x3ff0000000000000ULL);  /* NaN, 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL);  /* 1.0, NaN */
}

/* Test powers of 2 */
static void test_powers_of_2(void)
{
    emit(2.0, 0.0);
    emit(2.0, 1.0);
    emit(2.0, 2.0);
    emit(2.0, -1.0);
    emit(2.0, 0.5);
    emit(2.0, 10.0);
}

/* Test base 10 */
static void test_powers_of_10(void)
{
    emit(10.0, 0.0);
    emit(10.0, 1.0);
    emit(10.0, 2.0);
    emit(10.0, -1.0);
    emit(10.0, 0.5);
}

/* Test e */
static void test_powers_of_e(void)
{
    emit(2.718281828459045, 0.0);
    emit(2.718281828459045, 1.0);
    emit(2.718281828459045, 2.0);
    emit(2.718281828459045, -1.0);
}

/* Test fractional bases */
static void test_fractional_bases(void)
{
    emit(0.5, 1.0);
    emit(0.5, 2.0);
    emit(0.5, -1.0);
    emit(0.5, 0.5);
}

/* Test zero and one */
static void test_zero_and_one(void)
{
    emit(0.0, 0.0);
    emit(0.0, 1.0);
    emit(0.0, -1.0);
    emit(0.0, 2.0);
    emit(1.0, 1000.0);
}

/* Test negative bases */
