static void test_sweep(void)
{
    int orders[] = { 0, 1, 2 };
    int norders = sizeof(orders) / sizeof(orders[0]);
    int nsteps = 50;
    double lo = 0.5;
    double hi = 10.0;
    double step = (hi - lo) / (double)nsteps;

    for (int n = 0; n < norders; n++) {
        for (int i = 0; i <= nsteps; i++)
            emit(orders[n], lo + (double)i * step);
    }
}

/* ------------------------------------------------------------------ */

int main(void)
{
    test_special();
    test_tiny();
    test_known();
    test_large();
    test_order_range();
    test_domain_errors();
    test_hard();
    test_sweep();
    return 0;
}
